const data = items[0].json;

// 🔹 Dados básicos
const contexto = data.contexto || "";
const resultados = data.resultados || [];
const numero = data.telefone || data.numero;

// 🔹 Normalizador
const getItem = (r) => r.item || r;

// 🔹 Separar por escopo
const nacionais = resultados.filter(r => getItem(r).escopo === "nacional");
const locais = resultados.filter(r => getItem(r).escopo === "local");

// 🔹 Ordenar por nota
const ordenarPorNota = (arr) =>
  [...arr].sort((a, b) => (getItem(b).nota ?? 0) - (getItem(a).nota ?? 0));

// 🔹 Selecionar
const topNacionais = ordenarPorNota(nacionais).slice(0, 2);
const topLocais = ordenarPorNota(locais).slice(0, 4); // 👈 aqui

// 🔹 Formatter
const formatarLista = (lista) => {
  return lista
    .map((r) => {
      const item = getItem(r);
      const nome = item.razao_social || "Fornecedor";
      const modelo = item.modelo_negocio ? ` (${item.modelo_negocio})` : "";
      const site = item.site || "";
      return `- ${nome}${modelo}\n${site}`;
    })
    .join("\n");
};

// 🔹 Blocos
let blocoNacionais = "";
if (topNacionais.length > 0) {
  blocoNacionais = `Nacionais:\n${formatarLista(topNacionais)}`;
}

let blocoLocais = "";
if (topLocais.length > 0) {
  blocoLocais = `Locais:\n${formatarLista(topLocais)}`;
}

// 🔹 Contagem restante
const totalExibidos = topNacionais.length + topLocais.length;
const totalRestante = Math.max(0, resultados.length - totalExibidos);

// 🔹 Linha de contexto
const linhaContexto = contexto
  ? `Separei alguns fornecedores pra "${contexto}".`
  : `Separei alguns fornecedores pra você.`;

// 🔹 Mensagem
let mensagem = `Da uma olhada nesses fornecedores aqui:\n\n${linhaContexto}`;

if (blocoNacionais) {
  mensagem += `\n\n${blocoNacionais}`;
}

if (blocoLocais) {
  mensagem += `\n\n${blocoLocais}`;
}

if (totalRestante > 0) {
  mensagem += `\n\nTem mais ${totalRestante} fornecedores na plataforma, com contatos e detalhes completos.`;
}

mensagem += `\n\nVocê já pode acessar tudo direto pelo site:\n\n${data.url || "https://buscafornecedor.com.br"}`;

mensagem += `\n\nQualquer coisa, só me chamar por aqui.`;

// 🔹 Retorno
return [
  {
    json: {
      number: numero,
      text: mensagem
    }
  }
];

